arguments.command:
python3 -c "
import pandas as pd
import glob

for f in sorted(glob.glob('/app/*.csv')):
    try:
        df = pd.read_csv(f, nrows=1)
        rep_cols = [c for c in df.columns if 'rep' in c.lower()]
        if rep_cols:
            print(f, 'has columns:', rep_cols)
    except Exception as e:
        print(f, 'error:', e)
"

